const { ethers } = require("ethers");

// ABI definitions
const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)",
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

const DEX_ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)",
  "function getAmountsIn(uint256 amountOut, address[] calldata path) view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function swapTokensForExactTokens(uint256 amountOut, uint256 amountInMax, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function swapExactETHForTokens(uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) payable returns (uint256[] memory amounts)",
  "function swapExactTokensForETH(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function WETH() view returns (address)",
  "function factory() view returns (address)"
];

const DEX_FACTORY_ABI = [
  "function getPair(address tokenA, address tokenB) view returns (address pair)"
];

const DEX_PAIR_ABI = [
  "function getReserves() view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast)",
  "function token0() view returns (address)",
  "function token1() view returns (address)"
];

// Maximum uint256 value for unlimited approval
const MAX_UINT256 = ethers.MaxUint256;

// Default slippage tolerance (0.5%)
const DEFAULT_SLIPPAGE_BPS = 50;

// Default transaction deadline (20 minutes from now)
const DEFAULT_DEADLINE_MINUTES = 20;

class TokenSwapDApp {
  constructor(config = {}) {
    this.provider = null;
    this.signer = null;
    this.routerAddress = config.routerAddress || null;
    this.routerContract = null;
    this.factoryContract = null;
    this.wethAddress = null;
    this.slippageBps = config.slippageBps || DEFAULT_SLIPPAGE_BPS;
    this.deadlineMinutes = config.deadlineMinutes || DEFAULT_DEADLINE_MINUTES;
    this.tokenCache = new Map();
    this.eventListeners = new Map();
  }

  // ==================== Connection ====================

  async connectWithBrowserWallet() {
    if (typeof window === "undefined" || !window.ethereum) {
      throw new Error("No browser wallet detected. Please install MetaMask or a compatible wallet.");
    }

    await window.ethereum.request({ method: "eth_requestAccounts" });
    this.provider = new ethers.BrowserProvider(window.ethereum);
    this.signer = await this.provider.getSigner();

    await this._initializeRouter();

    const address = await this.signer.getAddress();
    const network = await this.provider.getNetwork();

    console.log(`Connected: ${address} on chain ${network.chainId}`);

    // Listen for account and chain changes
    window.ethereum.on("accountsChanged", async (accounts) => {
      if (accounts.length === 0) {
        console.log("Wallet disconnected");
        this._emit("disconnected");
      } else {
        this.signer = await this.provider.getSigner();
        console.log(`Account changed: ${accounts[0]}`);
        this._emit("accountChanged", accounts[0]);
      }
    });

    window.ethereum.on("chainChanged", (chainId) => {
      console.log(`Chain changed to ${chainId}. Reloading...`);
      this._emit("chainChanged", chainId);
    });

    return { address, chainId: network.chainId.toString() };
  }

  async connectWithProvider(providerUrl, privateKey) {
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    if (privateKey) {
      this.signer = new ethers.Wallet(privateKey, this.provider);
    }

    await this._initializeRouter();

    const address = this.signer ? await this.signer.getAddress() : null;
    const network = await this.provider.getNetwork();

    console.log(`Connected to ${providerUrl} on chain ${network.chainId}`);
    if (address) console.log(`Signer: ${address}`);

    return { address, chainId: network.chainId.toString() };
  }

  async _initializeRouter() {
    if (!this.routerAddress) {
      throw new Error("Router address must be set in config.");
    }

    this.routerContract = new ethers.Contract(
      this.routerAddress,
      DEX_ROUTER_ABI,
      this.signer || this.provider
    );

    try {
      this.wethAddress = await this.routerContract.WETH();
      const factoryAddress = await this.routerContract.factory();
      this.factoryContract = new ethers.Contract(
        factoryAddress,
        DEX_FACTORY_ABI,
        this.provider
      );
      console.log(`Router initialized. WETH: ${this.wethAddress}`);
    } catch (error) {
      throw new Error(`Failed to initialize router at ${this.routerAddress}: ${error.message}`);
    }
  }

  // ==================== Token Information ====================

  async getTokenInfo(tokenAddress) {
    if (this.tokenCache.has(tokenAddress)) {
      return this.tokenCache.get(tokenAddress);
    }

    const contract = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);

    try {
      const [name, symbol, decimals] = await Promise.all([
        contract.name(),
        contract.symbol(),
        contract.decimals()
      ]);

      const info = {
        address: tokenAddress,
        name,
        symbol,
        decimals: Number(decimals),
        contract
      };

      this.tokenCache.set(tokenAddress, info);
      return info;
    } catch (error) {
      throw new Error(`Failed to fetch token info for ${tokenAddress}: ${error.message}`);
    }
  }

  async getTokenBalance(tokenAddress, walletAddress = null) {
    const address = walletAddress || (this.signer ? await this.signer.getAddress() : null);
    if (!address) throw new Error("No wallet address provided or connected.");

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const balance = await tokenInfo.contract.balanceOf(address);

    return {
      raw: balance,
      formatted: ethers.formatUnits(balance, tokenInfo.decimals),
      decimals: tokenInfo.decimals,
      symbol: tokenInfo.symbol
    };
  }

  async getETHBalance(walletAddress = null) {
    const address = walletAddress || (this.signer ? await this.signer.getAddress() : null);
    if (!address) throw new Error("No wallet address provided or connected.");

    const balance = await this.provider.getBalance(address);
    return {
      raw: balance,
      formatted: ethers.formatEther(balance)
    };
  }

  // ==================== Allowance & Approval ====================

  async checkAllowance(tokenAddress, ownerAddress = null) {
    const owner = ownerAddress || (this.signer ? await this.signer.getAddress() : null);
    if (!owner) throw new Error("No owner address provided or connected.");

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const allowance = await tokenInfo.contract.allowance(owner, this.routerAddress);

    return {
      raw: allowance,
      formatted: ethers.formatUnits(allowance, tokenInfo.decimals),
      isUnlimited: allowance >= MAX_UINT256 / 2n,
      isZero: allowance === 0n
    };
  }

  async approveToken(tokenAddress, amount = null) {
    if (!this.signer) throw new Error("No signer connected. Cannot send transactions.");

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);

    // Use MAX_UINT256 for unlimited approval if no specific amount given
    const approvalAmount = amount
      ? ethers.parseUnits(amount.toString(), tokenInfo.decimals)
      : MAX_UINT256;

    console.log(
      `Approving ${amount ? amount + " " + tokenInfo.symbol : "unlimited " + tokenInfo.symbol} for router ${this.routerAddress}...`
    );

    try {
      const tx = await tokenContract.approve(this.routerAddress, approvalAmount);
      console.log(`Approval tx sent: ${tx.hash}`);

      const receipt = await tx.wait();
      console.log(`Approval confirmed in block ${receipt.blockNumber}`);

      this._emit("approval", {
        token: tokenAddress,
        symbol: tokenInfo.symbol,
        amount: approvalAmount === MAX_UINT256 ? "unlimited" : amount.toString(),
        txHash: tx.hash,
        blockNumber: receipt.blockNumber
      });

      return {
        txHash: tx.hash,
        blockNumber: receipt.blockNumber,
        approved: true,
        amount: approvalAmount === MAX_UINT256 ? "unlimited" : amount.toString()
      };
    } catch (error) {
      throw new Error(`Approval failed for ${tokenInfo.symbol}: ${error.message}`);
    }
  }

  async ensureAllowance(tokenAddress, requiredAmount) {
    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const requiredRaw = ethers.parseUnits(requiredAmount.toString(), tokenInfo.decimals);

    const allowance = await this.checkAllowance(tokenAddress);

    if (allowance.raw >= requiredRaw) {
      console.log(`Sufficient allowance for ${tokenInfo.symbol}: ${allowance.formatted}`);
      return { alreadyApproved: true, allowance: allowance.formatted };
    }

    console.log(
      `Insufficient allowance for ${tokenInfo.symbol}. Current: ${allowance.formatted}, Required: ${requiredAmount}. Requesting unlimited approval...`
    );

    // Approve MAX_UINT256 for convenience so future swaps don't need re-approval
    const approvalResult = await this.approveToken(tokenAddress);
    return { alreadyApproved: false, ...approvalResult };
  }

  // ==================== Price Quotes ====================

  async getAmountsOut(amountIn, path) {
    const tokenInInfo = await this.getTokenInfo(path[0]);
    const tokenOutInfo = await this.getTokenInfo(path[path.length - 1]);

    const amountInRaw = ethers.parseUnits(amountIn.toString(), tokenInInfo.decimals);

    try {
      const amounts = await this.routerContract.getAmountsOut(amountInRaw, path);

      const amountOut = amounts[amounts.length - 1];
      return {
        amountIn: amountIn.toString(),
        amountInRaw: amountInRaw,
        amountOut: ethers.formatUnits(amountOut, tokenOutInfo.decimals),
        amountOutRaw: amountOut,
        path,
        intermediateAmounts: amounts.map((a, i) => {
          if (i === 0) return amountIn.toString();
          if (i === amounts.length - 1)
            return ethers.formatUnits(a, tokenOutInfo.decimals);
          return a.toString();
        }),
        priceImpact: null // Would require reserve data for accurate calculation
      };
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}. The pair may not exist or have insufficient liquidity.`);
    }
  }

  async getAmountsIn(amountOut, path) {
    const tokenInInfo = await this.getTokenInfo(path[0]);
    const tokenOutInfo = await this.getTokenInfo(path[path.length - 1]);

    const amountOutRaw = ethers.parseUnits(amountOut.toString(), tokenOutInfo.decimals);

    try {
      const amounts = await this.routerContract.getAmountsIn(amountOutRaw, path);

      const amountIn = amounts[0];
      return {
        amountIn: ethers.formatUnits(amountIn, tokenInInfo.decimals),
        amountInRaw: amountIn,
        amountOut: amountOut.toString(),
        amountOutRaw: amountOutRaw,
        path
      };
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}. The pair may not exist or have insufficient liquidity.`);
    }
  }

  async getSwapQuote(tokenInAddress, tokenOutAddress, amountIn) {
    // Try direct path first
    const directPath = [tokenInAddress, tokenOutAddress];
    let bestQuote = null;

    try {
      bestQuote = await this.getAmountsOut(amountIn, directPath);
      bestQuote.route = "direct";
    } catch {
      // Direct path failed, will try through WETH
    }

    // Try path through WETH if different from both tokens
    if (
      this.wethAddress &&
      tokenInAddress.toLowerCase() !== this.wethAddress.toLowerCase() &&
      tokenOutAddress.toLowerCase() !== this.wethAddress.toLowerCase()
    ) {
      const wethPath = [tokenInAddress, this.wethAddress, tokenOutAddress];
      try {
        const wethQuote = await this.getAmountsOut(amountIn, wethPath);
        wethQuote.route = "via WETH";

        if (!bestQuote || wethQuote.amountOutRaw > bestQuote.amountOutRaw) {
          bestQuote = wethQuote;
        }
      } catch {
        // WETH path also failed
      }
    }

    if (!bestQuote) {
      throw new Error("No valid swap route found between the given tokens.");
    }

    // Calculate minimum amount out with slippage
    const slippageMultiplier = 10000n - BigInt(this.slippageBps);
    const minAmountOut = (bestQuote.amountOutRaw * slippageMultiplier) / 10000n;
    const tokenOutInfo = await this.getTokenInfo(tokenOutAddress);

    bestQuote.minAmountOut = ethers.formatUnits(minAmountOut, tokenOutInfo.decimals);
    bestQuote.minAmountOutRaw = minAmountOut;
    bestQuote.slippageBps = this.slippageBps;
    bestQuote.slippagePercent = (this.slippageBps / 100).toFixed(2) + "%";

    return bestQuote;
  }

  // ==================== Pair & Reserve Info ====================

  async getPairInfo(tokenAAddress, tokenBAddress) {
    if (!this.factoryContract) throw new Error("Factory contract not initialized.");

    const pairAddress = await this.factoryContract.getPair(tokenAAddress, tokenBAddress);

    if (pairAddress === ethers.ZeroAddress) {
      return { exists: false, pairAddress: null };
    }

    const pairContract = new ethers.Contract(pairAddress, DEX_PAIR_ABI, this.provider);
    const [reserves, token0, token1] = await Promise.all([
      pairContract.getReserves(),
      pairContract.token0(),
      pairContract.token1()
    ]);

    const token0Info = await this.getTokenInfo(token0);
    const token1Info = await this.getTokenInfo(token1);

    return {
      exists: true,
      pairAddress,
      token0: {
        address: token0,
        symbol: token0Info.symbol,
        reserve: ethers.formatUnits(reserves[0], token0Info.decimals)
      },
      token1: {
        address: token1,
        symbol: token1Info.symbol,
        reserve: ethers.formatUnits(reserves[1], token1Info.decimals)
      }
    };
  }

  // ==================== Swap Execution ====================

  _getDeadline() {
    return Math.floor(Date.now() / 1000) + this.deadlineMinutes * 60;
  }

  async swapExactTokensForTokens(tokenInAddress, tokenOutAddress, amountIn, options = {}) {
    if (!this.signer) throw new Error("No signer connected. Cannot send transactions.");

    const userAddress = await this.signer.getAddress();
    const tokenInInfo = await this.getTokenInfo(tokenInAddress);
    const tokenOutInfo = await this.getTokenInfo(tokenOutAddress);

    console.log(`\n=== Swap: ${amountIn} ${tokenInInfo.symbol} → ${tokenOutInfo.symbol} ===`);

    // Step 1: Get quote
    const quote = await this.getSwapQuote(tokenInAddress, tokenOutAddress, amountIn);
    console.log(`Expected output: ${quote.amountOut} ${tokenOutInfo.symbol}`);
    console.log(`Minimum output (${quote.slippagePercent} slippage): ${quote.minAmountOut} ${tokenOutInfo.symbol}`);
    console.log(`Route: ${quote.route}`);

    // Step 2: Check balance
    const balance = await this.getTokenBalance(tokenInAddress);
    const amountInRaw = ethers.parseUnits(amountIn.toString(), tokenInInfo.decimals);
    if (balance.raw < amountInRaw) {
      throw new Error(
        `Insufficient ${tokenInInfo.symbol} balance. Have: ${balance.formatted}, Need: ${amountIn}`
      );
    }

    // Step 3: Ensure approval (unlimited for convenience)
    const approvalResult = await this.ensureAllowance(tokenInAddress, amountIn);
    if (!approvalResult.alreadyApproved) {
      console.log(`Approval granted: ${approvalResult.txHash}`);
    }

    // Step 4: Execute swap
    const deadline = options.deadline || this._getDeadline();
    const recipient = options.recipient || userAddress;
    const minAmountOut = options.minAmountOut
      ? ethers.parseUnits(options.minAmountOut.toString(), tokenOutInfo.decimals)
      : quote.minAmountOutRaw;

    console.log(`Executing swap...`);

    try {
      const tx = await this.routerContract.swapExactTokensForTokens(
        amountInRaw,
        minAmountOut,
        quote.path,
        recipient,
        deadline,
        {
          gasLimit: options.gasLimit || undefined
        }
      );

      console.log(`Swap tx sent: ${tx.hash}`);
      this._emit("swapSubmitted", { txHash: tx.hash });

      const receipt = await tx.wait();
      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      // Parse transfer events to find actual amounts
      const swapResult = this._parseSwapReceipt(receipt, tokenInAddress, tokenOutAddress, tokenInInfo, tokenOutInfo);

      const result = {
        txHash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        tokenIn: tokenInInfo.symbol,
        tokenOut: tokenOutInfo.symbol,
        amountIn: amountIn.toString(),
        expectedAmountOut: quote.amountOut,
        minAmountOut: ethers.formatUnits(minAmountOut, tokenOutInfo.decimals),
        ...swapResult,
        route: quote.route,
        path: quote.path
      };

      this._emit("swapCompleted", result);
      return result;
    } catch (error) {
      this._emit("swapFailed", { error: error.message });
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async swapExactETHForTokens(tokenOutAddress, ethAmount, options = {}) {
    if (!this.signer) throw new Error("No signer connected. Cannot send transactions.");

    const userAddress = await this.signer.getAddress();
    const tokenOutInfo = await this.getTokenInfo(tokenOutAddress);
    const amountInWei = ethers.parseEther(ethAmount.toString());

    console.log(`\n=== Swap: ${ethAmount} ETH → ${tokenOutInfo.symbol} ===`);

    const path = [this.wethAddress, tokenOutAddress];

    // Get quote
    const amounts = await this.routerContract.getAmountsOut(amountInWei, path);
    const expectedOut = amounts[amounts.length - 1];
    const slippageMultiplier = 10000n - BigInt(this.slippageBps);
    const minAmountOut = options.minAmountOut
      ? ethers.parseUnits(options.minAmountOut.toString(), tokenOutInfo.decimals)
      : (expectedOut * slippageMultiplier) / 10000n;

    console.log(`Expected output: ${ethers.formatUnits(expectedOut, tokenOutInfo.decimals)} ${tokenOutInfo.symbol}`);

    // Check ETH balance
    const ethBalance = await this.getETHBalance();
    if (ethBalance.raw < amountInWei) {
      throw new Error(`Insufficient ETH balance. Have: ${ethBalance.formatted}, Need: ${ethAmount}`);
    }

    const deadline = options.deadline || this._getDeadline();
    const recipient = options.recipient || userAddress;

    try {
      const tx = await this.routerContract.swapExactETHForTokens(
        minAmountOut,
        path,
        recipient,
        deadline,
        {
          value: amountInWei,
          gasLimit: options.gasLimit || undefined
        }
      );

      console.log(`Swap tx sent: ${tx.hash}`);
      const receipt = await tx.wait();
      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      const result = {
        txHash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        tokenIn: "ETH",
        tokenOut: tokenOutInfo.symbol,
        amountIn: ethAmount.toString(),
        expectedAmountOut: ethers.formatUnits(expectedOut, tokenOutInfo.decimals),
        path
      };

      this._emit("swapCompleted", result);
      return result;
    } catch (error) {
      this._emit("swapFailed", { error: error.message });
      throw new Error(`Swap ETH→Token failed: ${error.message}`);
    }
  }

  async swapExactTokensForETH(tokenInAddress, amountIn, options = {}) {
    if (!this.signer) throw new Error("No signer connected. Cannot send transactions.");

    const userAddress = await this.signer.getAddress();
    const tokenInInfo = await this.getTokenInfo(tokenInAddress);
    const amountInRaw = ethers.parseUnits(amountIn.toString(), tokenInInfo.decimals);

    console.log(`\n=== Swap: ${amountIn} ${tokenInInfo.symbol} → ETH ===`);

    const path = [tokenInAddress, this.wethAddress];

    // Get quote
    const amounts = await this.routerContract.getAmountsOut(amountInRaw, path);
    const expectedOut = amounts[amounts.length - 1];
    const slippageMultiplier = 10000n - BigInt(this.slippageBps);
    const minAmountOut = options.minAmountOut
      ? ethers.parseEther(options.minAmountOut.toString())
      : (expectedOut * slippageMultiplier) / 10000n;

    console.log(`Expected output: ${ethers.formatEther(expectedOut)} ETH`);

    // Check balance
    const balance = await this.getTokenBalance(tokenInAddress);
    if (balance.raw < amountInRaw) {
      throw new Error(`Insufficient ${tokenInInfo.symbol} balance. Have: ${balance.formatted}, Need: ${amountIn}`);
    }

    // Ensure approval
    await this.ensureAllowance(tokenInAddress, amountIn);

    const deadline = options.deadline || this._getDeadline();
    const recipient = options.recipient || userAddress;

    try {
      const tx = await this.routerContract.swapExactTokensForETH(
        amountInRaw,
        minAmountOut,
        path,
        recipient,
        deadline,
        {
          gasLimit: options.gasLimit || undefined
        }
      );

      console.log(`Swap tx sent: ${tx.hash}`);
      const receipt = await tx.wait();
      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      const result = {
        txHash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        tokenIn: tokenInInfo.symbol,
        tokenOut: "ETH",
        amountIn: amountIn.toString(),
        expectedAmountOut: ethers.formatEther(expectedOut),
        path
      };

      this._emit("swapCompleted", result);
      return result;
    } catch (error) {
      this._emit("swapFailed", { error: error.message });
      throw new Error(`Swap Token→ETH failed: ${error.message}`);
    }
  }

  // ==================== Multi-hop Swap ====================

  async swapWithCustomPath(path, amountIn, options = {}) {
    if (!this.signer) throw new Error("No signer connected.");
    if (path.length < 2) throw new Error("Path must contain at least 2 token addresses.");

    const tokenInInfo = await this.getTokenInfo(path[0]);
    const tokenOutInfo = await this.getTokenInfo(path[path.length - 1]);
    const amountInRaw = ethers.parseUnits(amountIn.toString(), tokenInInfo.decimals);

    console.log(`\n=== Multi-hop Swap: ${amountIn} ${tokenInInfo.symbol} → ${tokenOutInfo.symbol} (${path.length - 1} hops) ===`);

    // Get quote
    const amounts = await this.routerContract.getAmountsOut(amountInRaw, path);
    const expectedOut = amounts[amounts.length - 1];
    const slippageMultiplier = 10000n - BigInt(this.slippageBps);
    const minAmountOut = options.minAmountOut
      ? ethers.parseUnits(options.minAmountOut.toString(), tokenOutInfo.decimals)
      : (expectedOut * slippageMultiplier) / 10000n;

    // Check balance & allowance
    const balance = await this.getTokenBalance(path[0]);
    if (balance.raw < amountInRaw) {
      throw new Error(`Insufficient ${tokenInInfo.symbol} balance.`);
    }

    await this.ensureAllowance(path[0], amountIn);

    const userAddress = await this.signer.getAddress();
    const deadline = options.deadline || this._getDeadline();
    const recipient = options.recipient || userAddress;

    try {
      const tx = await this.routerContract.swapExactTokensForTokens(
        amountInRaw,
        minAmountOut,
        path,
        recipient,
        deadline,
        { gasLimit: options.gasLimit || undefined }
      );

      console.log(`Multi-hop swap tx sent: ${tx.hash}`);
      const receipt = await tx.wait();
      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      return {
        txHash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        tokenIn: tokenInInfo.symbol,
        tokenOut: tokenOutInfo.symbol,
        amountIn: amountIn.toString(),
        expectedAmountOut: ethers.formatUnits(expectedOut, tokenOutInfo.decimals),
        minAmountOut: ethers.formatUnits(minAmountOut, tokenOutInfo.decimals),
        hops: path.length - 1,
        path
      };
    } catch (error) {
      throw new Error(`Multi-hop swap failed: ${error.message}`);
    }
  }

  // ==================== Batch Operations ====================

  async getMultipleBalances(tokenAddresses, walletAddress = null) {
    const results = {};
    const promises = tokenAddresses.map(async (addr) => {
      try {
        const balance = await this.getTokenBalance(addr, walletAddress);
        results[addr] = balance;
      } catch (error) {
        results[addr] = { error: error.message };
      }
    });

    await Promise.all(promises);
    return results;
  }

  async getMultipleAllowances(tokenAddresses, ownerAddress = null) {
    const results = {};
    const promises = tokenAddresses.map(async (addr) => {
      try {
        const allowance = await this.checkAllowance(addr, ownerAddress);
        results[addr] = allowance;
      } catch (error) {
        results[addr] = { error: error.message };
      }
    });

    await Promise.all(promises);
    return results;
  }

  async batchApprove(tokenAddresses) {
    const results = [];
    for (const tokenAddress of tokenAddresses) {
      try {
        const result = await this.approveToken(tokenAddress);
        results.push({ tokenAddress, ...result });
      } catch (error) {
        results.push({ tokenAddress, error: error.message, approved: false });
      }
    }
    return results;
  }

  // ==================== Settings ====================

  setSlippage(bps) {
    if (bps < 0 || bps > 5000) {
      throw new Error("Slippage must be between 0 and 5000 basis points (0% - 50%).");
    }
    this.slippageBps = bps;
    console.log(`Slippage set to ${(bps / 100).toFixed(2)}%`);
  }

  setDeadline(minutes) {
    if (minutes < 1 || minutes > 180) {
      throw new Error("Deadline must be between 1 and 180 minutes.");
    }
    this.deadlineMinutes = minutes;
    console.log(`Deadline set to ${minutes} minutes`);
  }

  // ==================== Utility ====================

  _parseSwapReceipt(receipt, tokenInAddress, tokenOutAddress, tokenInInfo, tokenOutInfo) {
    const transferTopic = ethers.id("Transfer(address,address,uint256)");
    const result = {};

    for (const log of receipt.logs) {
      if (log.topics[0] === transferTopic) {
        try {
          const tokenContract = new ethers.Contract(log.address, ERC20_ABI, this.provider);
          const parsed = tokenContract.interface.parseLog({
            topics: log.topics,
            data: log.data
          });

          if (log.address.toLowerCase() === tokenOutAddress.toLowerCase()) {
            result.actualAmountOut = ethers.formatUnits(parsed.args[2], tokenOutInfo.decimals);
          }
          if (log.address.toLowerCase() === tokenInAddress.toLowerCase()) {
            result.actualAmountIn = ethers.formatUnits(parsed.args[2], tokenInInfo.decimals);
          }
        } catch {
          // Skip unparseable logs
        }
      }
    }

    return result;
  }

  // ==================== Event System ====================

  on(event, callback) {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, []);
    }
    this.eventListeners.get(event).push(callback);
  }

  off(event, callback) {
    if (this.eventListeners.has(event)) {
      const listeners = this.eventListeners.get(event);
      const index = listeners.indexOf(callback);
      if (index !== -1) listeners.splice(index, 1);
    }
  }

  _emit(event, data) {
    if (this.eventListeners.has(event)) {
      for (const cb of this.eventListeners.get(event)) {
        try {
          cb(data);
        } catch (err) {
          console.error(`Error in event listener for '${event}':`, err);
        }
      }
    }
  }

  // ==================== Revoke Approval ====================

  async revokeApproval(tokenAddress) {
    if (!this.signer) throw new Error("No signer connected.");

    const tokenInfo = await this.getTokenInfo(tokenAddress);
    const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);

    console.log(`Revoking approval for ${tokenInfo.symbol} on router ${this.routerAddress}...`);

    const tx = await tokenContract.approve(this.routerAddress, 0);
    console.log(`Revoke tx sent: ${tx.hash}`);

    const receipt = await tx.wait();
    console.log(`Approval revoked in block ${receipt.blockNumber}`);

    return {
      txHash: tx.hash,
      blockNumber: receipt.blockNumber,
      symbol: tokenInfo.symbol,
      revoked: true
    };
  }
}

